package com.example.lessondesign.util; public class ApiAuthUtil { public static String buildSignature(String appId,String secret,long ts){ try{ java.security.MessageDigest md=java.security.MessageDigest.getInstance("MD5"); byte[] d=md.digest((appId+ts).getBytes("UTF-8")); StringBuilder sb=new StringBuilder(); for(byte b:d) sb.append(String.format("%02x",b)); javax.crypto.Mac mac=javax.crypto.Mac.getInstance("HmacSHA1"); mac.init(new javax.crypto.spec.SecretKeySpec(secret.getBytes("UTF-8"),"HmacSHA1")); return java.util.Base64.getEncoder().encodeToString(mac.doFinal(sb.toString().getBytes("UTF-8"))); }catch(Exception e){ return null; } } }